-- Dad Challenge Content Seed Data
-- 7 pillars x 9 phases = 63 entries
-- Updated: 2026-03-19
-- Idempotent: uses ON CONFLICT (pillar, phase) DO UPDATE

INSERT INTO dad_challenge_content (pillar, phase, headline, preview, icon, narrative, action_items, dad_quotes, sort_order, is_premium)
VALUES

-- =============================================================================
-- KNOWLEDGE PILLAR (pillar 1 of 7)
-- Learning about baby development, health, and safety
-- =============================================================================

('knowledge', 'pre-pregnancy', 'Get the Basics Down', 'Build your foundation of baby knowledge before conception.', 'BookOpen',
 'You don''t need a medical degree, but understanding the fundamentals of conception, prenatal health, and what the first trimester looks like gives you a real advantage. This is your chance to learn on your own timeline, without the pressure of a ticking clock. Most dads wish they''d started here.',
 '[{"title": "Read a prenatal basics guide", "description": "Pick up ''The Expectant Father'' or a similar resource and read the first few chapters covering conception through first trimester."},{"title": "Learn about prenatal vitamins", "description": "Understand why folic acid matters before conception and what supplements your partner should be taking now."},{"title": "Research your health insurance", "description": "Review your plan''s maternity coverage, in-network OBs, and what prenatal visits are covered."},{"title": "Schedule a preconception checkup", "description": "Both partners should see their doctors. You should discuss family history, medications, and lifestyle factors."}]'::jsonb,
 '[{"quote": "I thought I''d figure it all out later. Starting early meant I actually understood what the doctor was saying at that first appointment.", "attribution": "Marcus, first-time dad"},{"quote": "Reading one chapter a week made it feel manageable instead of overwhelming.", "attribution": "James, dad of two"}]'::jsonb,
 1, false),

('knowledge', 'trimester-1', 'Decode the First Trimester', 'Understand what''s happening in weeks 1-13 and why your partner feels the way she does.', 'Microscope',
 'The first trimester is invisible from the outside but seismic on the inside. Your partner''s body is building an entire life support system from scratch. Understanding the biology behind the nausea, exhaustion, and mood shifts turns confusion into empathy. You can''t fix morning sickness, but you can stop wondering why she''s asleep at 7pm.',
 '[{"title": "Learn the week-by-week development", "description": "Follow along with a pregnancy app or book to know what''s forming each week — brain, heart, limbs. It makes it real."},{"title": "Understand first trimester symptoms", "description": "Nausea, fatigue, breast tenderness, food aversions — learn what causes each one so you can respond with support, not confusion."},{"title": "Know the key appointments", "description": "Dating ultrasound around week 8, NT scan at weeks 11-14. Know what they''re checking for and plan to attend."},{"title": "Learn about miscarriage risk", "description": "It''s uncomfortable but important. Understanding the statistics (and when risk drops significantly) helps manage anxiety for both of you."}]'::jsonb,
 '[{"quote": "When I understood that her body was literally building a placenta from scratch, the exhaustion made total sense.", "attribution": "David, dad of one"},{"quote": "Going to that first ultrasound prepared — knowing what we''d see and hear — made it an incredible moment instead of a confusing one.", "attribution": "Ryan, first-time dad"}]'::jsonb,
 1, false),

('knowledge', 'trimester-2', 'Level Up Your Baby Knowledge', 'The anatomy scan, kick counts, and what''s really happening in there.', 'Brain',
 'The second trimester is when pregnancy starts to feel real. You can see the bump, feel the kicks, and the anatomy scan gives you an actual look at your baby. This is the sweet spot for learning — your partner is feeling better, and there''s enough happening to make the knowledge stick. Use this window.',
 '[{"title": "Prepare for the anatomy scan", "description": "Around week 20, you''ll see detailed images of your baby. Learn what they check (organs, spine, limbs) so you can be present, not lost."},{"title": "Learn about fetal movement", "description": "Kicks start around weeks 18-22. Understand what''s normal, when to track, and when decreased movement matters."},{"title": "Study common second trimester tests", "description": "Glucose screening, Rh factor, quad screen — know what they test for and what the results mean."},{"title": "Research childbirth education classes", "description": "Now is the time to sign up. Hospital-based, Bradley Method, or online — pick one that fits your schedule."}]'::jsonb,
 '[{"quote": "Seeing our daughter''s spine on the anatomy scan — that was the moment I went from ''we''re having a baby'' to ''that''s my kid.''", "attribution": "Chris, dad of two"},{"quote": "Taking a childbirth class together was the best thing we did. I stopped feeling like a bystander.", "attribution": "Alex, first-time dad"}]'::jsonb,
 1, false),

('knowledge', 'trimester-3', 'Master the Final Stretch', 'Labor signs, delivery prep, and everything you need to know before D-day.', 'GraduationCap',
 'The third trimester is game time preparation. Your baby is viable, growing fast, and could arrive any time after week 37. This is where your knowledge directly translates to action — recognizing labor signs, understanding delivery options, and knowing what happens in an emergency. Don''t wing this part.',
 '[{"title": "Learn the stages of labor", "description": "Early labor, active labor, transition, pushing, delivery of placenta. Know what each stage looks like and how long they typically last."},{"title": "Understand intervention options", "description": "Epidural, pitocin, C-section, episiotomy — know what each one is, when it''s used, and what questions to ask."},{"title": "Know the warning signs", "description": "Preeclampsia symptoms, premature labor signs, when to call the doctor vs. go to the hospital. This knowledge matters."},{"title": "Study newborn basics now", "description": "Umbilical cord care, jaundice, feeding basics, safe sleep. You won''t have time to learn this after birth."}]'::jsonb,
 '[{"quote": "I made flashcards for labor signs. My wife laughed at me, but when her water broke at 3am, I was calm and she wasn''t.", "attribution": "Tom, dad of three"},{"quote": "Knowing the difference between Braxton Hicks and real contractions saved us two unnecessary hospital trips.", "attribution": "Miguel, first-time dad"}]'::jsonb,
 1, false),

('knowledge', '0-3-months', 'Survive and Learn the Newborn Phase', 'SIDS prevention, feeding basics, and reading your baby''s cues.', 'Baby',
 'The first three months are a crash course in keeping a tiny human alive. Everything is new, nothing is intuitive, and Google at 3am is a terrible doctor. Focus on the essentials: safe sleep, feeding, and learning your baby''s unique communication style. You''ll be amazed how fast you get fluent.',
 '[{"title": "Master safe sleep rules", "description": "Back to sleep, firm mattress, no loose bedding. Know the ABCs of safe sleep cold — this is non-negotiable."},{"title": "Learn feeding fundamentals", "description": "Whether breast or bottle, understand feeding cues, frequency, and how to tell if baby is getting enough."},{"title": "Decode baby cries", "description": "Hunger, tired, overstimulated, wet, gas — babies have different cries. Start learning your baby''s specific signals."},{"title": "Know when to call the pediatrician", "description": "Fever over 100.4 in a newborn is an ER visit. Learn the red flags that distinguish ''normal newborn stuff'' from ''call now.''"}]'::jsonb,
 '[{"quote": "By week three I could tell the difference between his hungry cry and his tired cry. That felt like a superpower.", "attribution": "Kevin, first-time dad"},{"quote": "The pediatrician told me ''you''ll call us too much at first, and that''s fine.'' That permission meant everything.", "attribution": "Andre, dad of one"}]'::jsonb,
 1, false),

('knowledge', '3-6-months', 'Track the Developmental Leaps', 'Rolling, laughing, solids introduction — your baby is changing fast.', 'TrendingUp',
 'Between 3 and 6 months, your baby transforms from a sleepy newborn into a social, rolling, laughing little person. Developmental milestones come fast — and understanding them helps you be an active participant, not just a witness. This is also when feeding gets interesting with the introduction of solids.',
 '[{"title": "Learn the 3-6 month milestones", "description": "Rolling over, reaching for objects, social smiling, babbling. Know what to expect and what''s worth mentioning to your pediatrician."},{"title": "Research starting solids", "description": "Around 4-6 months, you''ll introduce food. Understand readiness signs, first foods, and the difference between purees and baby-led weaning."},{"title": "Understand sleep development", "description": "Sleep regressions, nap transitions, and the 4-month sleep regression are real. Know what''s happening neurologically."},{"title": "Learn about tummy time progression", "description": "Tummy time builds the strength for crawling. Know how much, how often, and how to make it not miserable."}]'::jsonb,
 '[{"quote": "When he rolled over the first time, I was the one on the floor with him. I literally cheered.", "attribution": "Patrick, first-time dad"},{"quote": "Learning about wonder weeks helped me understand why she was suddenly fussy after weeks of being chill.", "attribution": "Sam, dad of two"}]'::jsonb,
 1, false),

('knowledge', '6-12-months', 'Navigate the Crawler Era', 'Crawling, first words, and understanding your baby''s rapidly expanding world.', 'Search',
 'Your baby is mobile now, and the world just got a lot bigger — and more dangerous. From crawling to cruising to possibly first steps, this period demands that you understand both development and safety at a deeper level. Your baby is also becoming a person with opinions, preferences, and a budding sense of humor.',
 '[{"title": "Childproof with real knowledge", "description": "Go beyond outlet covers. Understand choking hazards, furniture anchoring, water safety, and blind cord dangers from an informed perspective."},{"title": "Learn about language development", "description": "Babbling becomes words. Understand how to encourage language through narrating, reading, and responsive conversation."},{"title": "Understand separation anxiety", "description": "Around 8-10 months, your baby realizes you can leave. This is healthy development, not a problem to fix. Learn how to handle it."},{"title": "Study age-appropriate play", "description": "Cause-and-effect toys, peek-a-boo, stacking — learn what activities actually support brain development vs. just keep them busy."}]'::jsonb,
 '[{"quote": "I baby-proofed the house twice. The first time I did it from adult height. Then I crawled around on my hands and knees and found 15 more hazards.", "attribution": "Will, dad of two"},{"quote": "Reading to him every night since 6 months — by 11 months he was bringing me books. That''s my guy.", "attribution": "Jordan, first-time dad"}]'::jsonb,
 1, false),

('knowledge', '12-18-months', 'Understand Your Toddler', 'Walking, tantrums, and the explosion of personality.', 'Footprints',
 'Welcome to toddlerhood. Your child is walking (or about to), talking (sort of), and asserting independence at every opportunity. Tantrums are not misbehavior — they''re a developing brain overwhelmed by big emotions it can''t process yet. Understanding this changes everything about how you respond.',
 '[{"title": "Learn about toddler brain development", "description": "The prefrontal cortex won''t be fully developed for 20+ years. Understanding this explains tantrums, impulsivity, and why ''no'' doesn''t always work."},{"title": "Study positive discipline basics", "description": "Redirection, natural consequences, and setting boundaries with empathy. Start building your discipline toolkit now."},{"title": "Understand language explosion", "description": "Vocabulary grows from ~10 words to 50+ in this period. Learn how to support it through reading, narration, and patience."},{"title": "Research toddler nutrition", "description": "Picky eating starts here. Understand the division of responsibility: you decide what and when, they decide if and how much."}]'::jsonb,
 '[{"quote": "Once I understood that tantrums meant his brain was overwhelmed, not that he was being bad, I stopped getting frustrated and started getting curious.", "attribution": "Nate, dad of one"},{"quote": "The best parenting book I read was about toddler brain science. It should be required reading for every dad.", "attribution": "Derek, dad of three"}]'::jsonb,
 1, false),

('knowledge', '18-plus', 'Keep Growing With Your Kid', 'Big emotions, social skills, and staying one step ahead.', 'Compass',
 'Your toddler is becoming a little person with complex emotions, social awareness, and an opinion about everything. The challenges shift from physical safety to emotional coaching. Understanding their developmental stage helps you set realistic expectations and respond to meltdowns with confidence, not frustration.',
 '[{"title": "Learn about emotional regulation stages", "description": "Co-regulation before self-regulation. Your toddler needs you to be calm so they can learn to be calm. Understand the neuroscience."},{"title": "Study social development milestones", "description": "Parallel play, sharing, empathy — know what''s developmentally appropriate so you don''t expect more than they can give."},{"title": "Understand sleep transitions", "description": "Dropping naps, moving to a big kid bed, night fears. Know the signs and how to navigate each transition smoothly."},{"title": "Research preschool readiness", "description": "If preschool is on the horizon, understand what ''ready'' actually looks like and how to prepare without pressure."}]'::jsonb,
 '[{"quote": "My daughter''s preschool teacher told me the dads who understand development are the ones whose kids adjust fastest. That hit home.", "attribution": "Leo, dad of two"},{"quote": "I stopped saying ''you''re fine'' when he was upset and started saying ''that was really frustrating, huh?'' Night and day difference.", "attribution": "Eric, dad of one"}]'::jsonb,
 1, true),

-- =============================================================================
-- PLANNING PILLAR (pillar 2 of 7)
-- Preparing logistics, schedules, and practical needs
-- =============================================================================

('planning', 'pre-pregnancy', 'Plan Before the Plus Sign', 'Get your logistics in order before conception.', 'ClipboardList',
 'Planning before pregnancy isn''t about being controlling — it''s about giving your future family the best possible start. From health insurance to living space to career timing, the decisions you make now have outsized impact. This is the one time you can plan without the urgency of a due date.',
 '[{"title": "Audit your living space", "description": "Do you need to move? Can you convert a room? Start thinking about space now when you have time to be strategic."},{"title": "Review your health insurance", "description": "Open enrollment matters. Make sure your plan covers maternity, has a reasonable deductible, and includes your preferred providers."},{"title": "Build an emergency fund buffer", "description": "Aim for 3-6 months of expenses before conception. Medical bills, unpaid leave, and unexpected costs add up fast."},{"title": "Discuss parental leave plans", "description": "Know your company''s policy. Know your partner''s policy. Start thinking about timing and coverage."}]'::jsonb,
 '[{"quote": "We switched insurance plans during open enrollment before trying to conceive. Saved us almost $4,000 on delivery.", "attribution": "Matt, dad of one"},{"quote": "Having a plan didn''t make it less exciting. It made it less stressful.", "attribution": "Brian, dad of two"}]'::jsonb,
 2, false),

('planning', 'trimester-1', 'Set Up Your Support System', 'Appointments, communication plans, and early logistics.', 'Calendar',
 'The first trimester is mostly invisible to the outside world, but behind the scenes there''s a lot to organize. Prenatal appointments need scheduling, you need to decide when to tell people, and there are early decisions about providers and birth locations that are easier to make now than later.',
 '[{"title": "Create a shared pregnancy calendar", "description": "Add all appointments, key milestones, and deadlines. Google Calendar, Apple Calendar — whatever you both actually use."},{"title": "Research OB/midwife options", "description": "If you haven''t locked in a provider, now is the time. Ask about their philosophy, hospital affiliation, and after-hours availability."},{"title": "Develop your announcement plan", "description": "When to tell parents, friends, work. Have a plan so you''re not caught off guard by the question."},{"title": "Start a baby prep checklist", "description": "Not buying yet — just listing. What do you need? What can you borrow? What requires research?"}]'::jsonb,
 '[{"quote": "The shared calendar was simple but it changed everything. I stopped being the guy who asked ''when''s the appointment again?''", "attribution": "Jason, first-time dad"},{"quote": "We told our parents at 10 weeks and everyone else at 14. Having a plan meant no awkward accidental reveals.", "attribution": "Carlos, dad of one"}]'::jsonb,
 2, false),

('planning', 'trimester-2', 'Build Your Birth Plan', 'Hospital tours, birth preferences, and getting your ducks in a row.', 'FileText',
 'The second trimester is your planning sweet spot. Energy is up, the due date feels real but not imminent, and there''s time to be thoughtful instead of reactive. Hospital tours, birth plan conversations, nursery setup, and registry building all belong here. Future you will be grateful.',
 '[{"title": "Tour the hospital or birth center", "description": "Know where to park, where to check in, what the rooms look like. Familiarity reduces stress on delivery day."},{"title": "Draft birth preferences together", "description": "Pain management, who''s in the room, music, lighting, delayed cord clamping. Write it down but hold it loosely."},{"title": "Create or review your registry", "description": "Research big-ticket items (car seat, stroller, crib). Read reviews from dads, not just marketing copy."},{"title": "Plan the nursery or baby space", "description": "Even if it''s a corner of your room. Crib, changing area, feeding station, storage. Functional beats Instagram-worthy."}]'::jsonb,
 '[{"quote": "The hospital tour made me realize I had zero idea where anything was. On delivery day, I walked in like I owned the place.", "attribution": "Tyler, dad of one"},{"quote": "Our birth plan was one page. The doctor actually read it because it was concise. That mattered.", "attribution": "Ahmad, dad of two"}]'::jsonb,
 2, false),

('planning', 'trimester-3', 'Lock Down the Game Plan', 'Hospital bag, childcare, and the ''when it happens'' protocol.', 'Shield',
 'This is execution mode. The nursery needs to be ready, the hospital bag needs to be packed, and you need a clear protocol for when labor starts. Who do you call? Who watches the dog? What route do you take at rush hour? The dads who have a plan are the dads who stay calm.',
 '[{"title": "Pack the hospital bag", "description": "Her bag, your bag, baby''s bag. Chargers, snacks, change of clothes, going-home outfit. Pack it by week 36."},{"title": "Install the car seat", "description": "Many fire stations will check your installation for free. Do this by week 37 — don''t wait."},{"title": "Create the ''go time'' protocol", "description": "When to leave, who to call, what to grab. Write it on paper and stick it on the fridge. Phones die, paper doesn''t."},{"title": "Arrange postpartum support", "description": "Meal train, family visits, pet care, house cleaning. Line up help now so you''re not scrambling during recovery."}]'::jsonb,
 '[{"quote": "I had a laminated card in my wallet with the hospital address, doctor''s number, and our birth plan summary. Overkill? Maybe. But I never panicked.", "attribution": "Rob, dad of three"},{"quote": "Installing the car seat at 39 weeks in the dark was not my finest moment. Do it early.", "attribution": "Steve, first-time dad"}]'::jsonb,
 2, false),

('planning', '0-3-months', 'Organize the New Normal', 'Schedules, shifts, and making the chaos manageable.', 'LayoutGrid',
 'Newborn life feels like chaos, but it has patterns if you look for them. Establishing shared schedules, shift systems for night feeds, and basic routines gives both parents breathing room. You''re not trying to control the baby — you''re trying to create enough structure that you can both function.',
 '[{"title": "Establish a night shift system", "description": "Split the night into shifts so each parent gets at least one 4-hour stretch of uninterrupted sleep. Adjust weekly."},{"title": "Set up a feeding tracker", "description": "Whether breastfeeding or bottle, track times and amounts. It helps the pediatrician and helps you spot patterns."},{"title": "Plan your return to work", "description": "Know your start date, childcare arrangement, and transition plan. Communicate clearly with your employer."},{"title": "Create a visitor protocol", "description": "Who can visit, when, for how long, and what they should bring (food, not advice). Protect your recovery bubble."}]'::jsonb,
 '[{"quote": "The shift system saved our marriage. She took 8pm-1am, I took 1am-6am. We both got sleep. Revolutionary.", "attribution": "Dan, dad of one"},{"quote": "I made a Google Doc for visitors: bring food, wash your hands, 30 minutes max. People actually appreciated the clarity.", "attribution": "Jake, first-time dad"}]'::jsonb,
 2, false),

('planning', '3-6-months', 'Plan for Milestones Ahead', 'Childcare research, travel prep, and upcoming transitions.', 'Map',
 'You''ve survived the newborn fog. Now it''s time to plan ahead for the transitions coming fast: starting solids, possible sleep training, childcare arrangements, and maybe even travel with a baby. Planning in this window means you''re ready instead of reactive when these milestones hit.',
 '[{"title": "Research childcare options", "description": "Daycare tours, nanny interviews, family arrangements. Waitlists are real — start this process months before you need it."},{"title": "Plan the solid food introduction", "description": "High chair, first foods, feeding schedule. Decide your approach (purees, BLW, combo) before the 6-month mark."},{"title": "Schedule the 6-month pediatric visit", "description": "Milestone check, vaccines, and questions about sleep, feeding, and development. Prepare your questions in advance."},{"title": "Plan a practice outing or trip", "description": "A day trip or overnight stay that tests your packing, travel, and flexibility skills before attempting anything bigger."}]'::jsonb,
 '[{"quote": "We started daycare research at 4 months and still barely got a spot. Start early. I mean it.", "attribution": "Devon, dad of one"},{"quote": "Our first road trip with the baby was a 2-hour drive to my parents. Perfect training wheels.", "attribution": "Sean, dad of two"}]'::jsonb,
 2, false),

('planning', '6-12-months', 'Organize for Mobility', 'Baby-proofing plans, routine updates, and preparing for independence.', 'Home',
 'Your baby is on the move, which means your planning shifts from schedules to spaces. Baby-proofing needs to be thorough, routines need updating as naps change, and you might be navigating childcare transitions. This is also when planning for the first birthday starts — keep it simple.',
 '[{"title": "Do a comprehensive baby-proof audit", "description": "Get on your hands and knees and crawl through every room. Cabinet locks, outlet covers, furniture anchors, blind cords, toilet locks."},{"title": "Update daily routines for nap transitions", "description": "Moving from 3 naps to 2 changes the whole day. Adjust feeding times, activity windows, and bedtime accordingly."},{"title": "Plan for separation and childcare", "description": "If starting daycare or a new arrangement, plan the transition with short days and gradual increases."},{"title": "Start first birthday planning", "description": "Keep it simple and age-appropriate. The party is really for the adults — your baby just needs cake and a nap."}]'::jsonb,
 '[{"quote": "I spent a Saturday morning crawling around the house. Found a coin under the couch, a loose outlet cover, and a wobbly bookshelf. Time well spent.", "attribution": "Greg, dad of one"},{"quote": "The first birthday party was 10 people, homemade cake, and done by noon. Perfect.", "attribution": "Marcus, dad of two"}]'::jsonb,
 2, false),

('planning', '12-18-months', 'Plan for Toddler Life', 'Activity schedules, routine transitions, and preschool research.', 'ListChecks',
 'Toddlers thrive on routine but hate being bored. Your planning now revolves around creating consistent daily structure while building in enough variety and stimulation. You might also be starting to think about preschool, which in many areas requires planning a year or more in advance.',
 '[{"title": "Establish a toddler daily routine", "description": "Wake, meals, play, nap, outdoor time, bath, bed. Toddlers do best with predictability. Write it out and post it."},{"title": "Research local toddler activities", "description": "Library story time, swimming, music classes, playground groups. Build a weekly rotation that gets you both out of the house."},{"title": "Start preschool research", "description": "If you want a specific program, the waitlist might already be open. Tour facilities, ask about philosophy, check availability."},{"title": "Plan the nap-to-one transition", "description": "Most toddlers drop to one nap between 12-18 months. Plan how to adjust the schedule and have backup plans for cranky afternoons."}]'::jsonb,
 '[{"quote": "The weekly activity schedule saved our weekends. Instead of ''what do we do today?'' we just checked the plan.", "attribution": "Ian, dad of one"},{"quote": "We toured five preschools. The one we loved had a 14-month waitlist. Start early.", "attribution": "Phil, dad of two"}]'::jsonb,
 2, true),

('planning', '18-plus', 'Plan for the Big Kid Transition', 'Preschool prep, daily independence, and long-term family planning.', 'Rocket',
 'Your toddler is becoming increasingly independent, and your planning shifts to supporting that independence safely. Preschool transitions, potty training logistics, and establishing household responsibilities are on the horizon. This is also a natural point to think about long-term family goals.',
 '[{"title": "Prepare for preschool transition", "description": "Practice the routine: getting dressed, packing a bag, saying goodbye. Start weeks before the first day."},{"title": "Set up potty training logistics", "description": "Potty chair, training pants, cleaning supplies, reward system if you use one. Have everything ready before you start."},{"title": "Create age-appropriate responsibilities", "description": "Putting toys away, helping set the table, carrying their plate. Small jobs build confidence and routine."},{"title": "Discuss long-term family plans", "description": "Another child? Career moves? Housing changes? Have the conversation with your partner while things are relatively stable."}]'::jsonb,
 '[{"quote": "We practiced the preschool routine for two weeks before the first day. Drop-off was tears-free. For him, anyway.", "attribution": "Nick, dad of one"},{"quote": "Giving my toddler a ''job'' — carrying the napkins to the table — made dinner prep 10x smoother. She felt included.", "attribution": "Ben, dad of three"}]'::jsonb,
 2, true),

-- =============================================================================
-- FINANCES PILLAR (pillar 3 of 7)
-- Financial planning, budgeting, insurance, savings
-- =============================================================================

('finances', 'pre-pregnancy', 'Build Your Financial Foundation', 'Get your money right before baby changes everything.', 'PiggyBank',
 'Having a baby will cost money. A lot of it. But the dads who start financial planning before conception are the ones who don''t panic when the hospital bill arrives. This isn''t about being rich — it''s about being prepared. Emergency fund, insurance review, and an honest budget conversation with your partner.',
 '[{"title": "Calculate your current monthly expenses", "description": "Know exactly where your money goes. You can''t plan for new expenses if you don''t understand your existing ones."},{"title": "Build or top off your emergency fund", "description": "Target 3-6 months of expenses. Medical surprises, job changes, and unexpected costs hit harder with a newborn."},{"title": "Review life and disability insurance", "description": "If someone depends on your income, you need both. Get quotes now while you''re healthy and rates are lowest."},{"title": "Start a ''baby fund'' savings account", "description": "Even $100/month adds up. Open a dedicated account so baby money doesn''t mix with regular savings."}]'::jsonb,
 '[{"quote": "We saved $5,000 in a baby fund before she got pregnant. When the hospital bill came, we didn''t flinch.", "attribution": "Tony, dad of one"},{"quote": "Getting life insurance before pregnancy meant better rates. I''m glad my buddy told me that.", "attribution": "Omar, first-time dad"}]'::jsonb,
 3, false),

('finances', 'trimester-1', 'Face the Real Numbers', 'Understand what pregnancy and birth actually cost.', 'Calculator',
 'The average cost of having a baby in the US ranges from $5,000 to $11,000 with insurance. Without it, you''re looking at $30,000+. These numbers are scary but manageable if you face them now. Call your insurance, understand your deductible, and start building a realistic budget for the next 9 months.',
 '[{"title": "Call your insurance company", "description": "Ask specifically: what''s covered for prenatal, delivery, and postpartum? What''s your out-of-pocket max? Are there in-network requirements?"},{"title": "Estimate total pregnancy costs", "description": "Add up: prenatal visits, ultrasounds, delivery, hospital stay, postpartum care. Get real numbers, not guesses."},{"title": "Create a pregnancy budget", "description": "Monthly allocation for medical costs, baby gear, nursery setup, and maternity/paternity leave income gap."},{"title": "Research your FSA/HSA options", "description": "Flexible spending and health savings accounts can save you significant money on medical expenses. Max them out if possible."}]'::jsonb,
 '[{"quote": "I called insurance at week 8 and found out our deductible reset in January. We timed everything to stay in one calendar year and saved $3,000.", "attribution": "Raj, dad of one"},{"quote": "The spreadsheet was intimidating at first. But knowing the number was way less stressful than guessing.", "attribution": "Kyle, first-time dad"}]'::jsonb,
 3, false),

('finances', 'trimester-2', 'Budget for Baby Gear', 'Smart spending on what you actually need (and skipping what you don''t).', 'ShoppingCart',
 'The baby industrial complex wants you to believe you need $10,000 in gear. You don''t. A safe car seat, a crib, a way to feed the baby, diapers, and some onesies will cover the first month. Everything else is either a nice-to-have or a total waste. Learn the difference before the registry goes live.',
 '[{"title": "Research before you register", "description": "Read reviews from actual parents, not sponsored content. Focus on safety ratings and daily usability, not brand prestige."},{"title": "Identify borrow-and-buy-used items", "description": "Swings, bouncers, clothes, and toys are used for weeks. Car seats and cribs should be new. Know the difference."},{"title": "Set a gear budget and stick to it", "description": "Allocate a total number, track against it, and prioritize. You can always add things later — you can''t un-spend money."},{"title": "Factor in recurring costs", "description": "Diapers, wipes, formula (if applicable), laundry supplies. These monthly costs add up faster than one-time purchases."}]'::jsonb,
 '[{"quote": "We bought a $900 stroller because the blog said to. Used it maybe 20 times. The $200 umbrella stroller went everywhere.", "attribution": "Luke, dad of two"},{"quote": "Borrowed a swing, bought used clothes in bulk, splurged only on the car seat and crib. Saved thousands.", "attribution": "Marcus, first-time dad"}]'::jsonb,
 3, false),

('finances', 'trimester-3', 'Prepare for the Income Shift', 'Parental leave finances, hospital payment plans, and the first month.', 'Wallet',
 'If either of you is taking unpaid or partially paid leave, the income shift is coming. The third trimester is your last chance to build a cushion. Negotiate hospital payment plans, understand your leave benefits, and front-load any expenses you can handle now while both paychecks are still full.',
 '[{"title": "Model your leave income", "description": "Calculate exactly what your household income will be during leave. Include state benefits, employer coverage, and any gap you need to cover."},{"title": "Contact the hospital billing department", "description": "Ask about payment plans, prompt-pay discounts, and financial assistance programs. Most hospitals offer all three."},{"title": "Pre-pay what you can", "description": "Stock up on diapers, wipes, and household supplies. Prepay any bills you can. Reduce cash outflow during leave."},{"title": "Update your W-4 withholding", "description": "Adding a dependent changes your tax situation. Update your withholding to reflect the new household size."}]'::jsonb,
 '[{"quote": "I called the hospital and asked for a payment plan. Zero interest, 12 months. Never would have known if I didn''t ask.", "attribution": "Derek, dad of one"},{"quote": "We lived on my salary for two months before the baby came as a trial run. It was tight but it prepared us.", "attribution": "Jonathan, first-time dad"}]'::jsonb,
 3, false),

('finances', '0-3-months', 'Manage the Financial Shock', 'Track real costs, adjust the budget, and find hidden savings.', 'Receipt',
 'The bills are coming in and the spending is real. This is where your pre-baby budget meets reality. Track everything for the first month, identify where estimates were off, and adjust. Look for savings you might be missing — employer dependent care FSA, state benefits, tax credits. Every dollar counts right now.',
 '[{"title": "Track all baby-related spending for 30 days", "description": "Every diaper, every doctor visit, every Amazon order. Get a real number for your monthly baby costs."},{"title": "File for all available benefits", "description": "Dependent care FSA, state paid family leave, employer benefits, WIC if eligible. Leave nothing on the table."},{"title": "Adjust your monthly budget", "description": "Based on actual data, not estimates. Where did you overspend? Where can you cut back? Be honest."},{"title": "Open a 529 college savings account", "description": "Even $25/month starting now grows significantly over 18 years. Some states offer tax deductions for contributions."}]'::jsonb,
 '[{"quote": "We spent $350 on diapers and wipes the first month. Switched to a subscription service and cut it to $200.", "attribution": "Jeff, dad of one"},{"quote": "My state had a paid family leave benefit I almost didn''t apply for. It covered 60% of my salary for 8 weeks.", "attribution": "Chris, first-time dad"}]'::jsonb,
 3, false),

('finances', '3-6-months', 'Optimize Your New Normal', 'Childcare costs, return-to-work finances, and long-term planning.', 'BarChart3',
 'By now you have real data on what your family costs. It''s time to optimize. Childcare is likely your biggest new expense — understand all your options. If you''re both back at work, look at how dual income changes your tax picture. Start thinking about the long game: college savings, estate planning, and financial goals.',
 '[{"title": "Compare childcare cost structures", "description": "Daycare, nanny, nanny share, family care. Calculate true cost including taxes, commute, and schedule flexibility."},{"title": "Review your tax strategy", "description": "Child tax credit, dependent care credit, filing status changes. Run the numbers or talk to a tax professional."},{"title": "Automate savings contributions", "description": "Set up automatic transfers to 529, emergency fund, and retirement. Automation beats willpower every time."},{"title": "Review and update insurance", "description": "Is your baby on the best plan? Do you need to increase life insurance? Review all policies annually."}]'::jsonb,
 '[{"quote": "A nanny share with our neighbors was 40% cheaper than daycare and our kids got more attention. Win-win.", "attribution": "Dave, dad of two"},{"quote": "I set up a $50/month auto-transfer to his 529 account. In 18 years that''s over $10,000 before any growth.", "attribution": "Aaron, first-time dad"}]'::jsonb,
 3, false),

('finances', '6-12-months', 'Think Long-Term', 'Estate planning, education savings, and financial protection.', 'Landmark',
 'With the immediate financial chaos settling, it''s time to think bigger. You have a dependent now, which means estate planning isn''t optional — it''s urgent. A will, guardianship designation, and beneficiary updates protect your family if the worst happens. This isn''t morbid; it''s responsible.',
 '[{"title": "Create or update your will", "description": "Designate a guardian for your child. An online service works for basic wills, but consider an attorney for complex situations."},{"title": "Update all beneficiary designations", "description": "Life insurance, retirement accounts, bank accounts. Make sure everything reflects your current family structure."},{"title": "Increase life insurance if needed", "description": "Your coverage should replace your income for at least 10 years. If not, get additional term life coverage now."},{"title": "Set financial milestones for the year", "description": "Emergency fund target, debt payoff goals, savings rate. Write them down and review quarterly."}]'::jsonb,
 '[{"quote": "We didn''t have a will until our son was 8 months old. The thought of something happening without a guardian named was the push I needed.", "attribution": "Adam, dad of one"},{"quote": "Updating beneficiaries took 20 minutes online. Twenty minutes to make sure my family was protected. Do it.", "attribution": "Tyrone, dad of two"}]'::jsonb,
 3, true),

('finances', '12-18-months', 'Build Generational Wealth Habits', 'Teaching money, increasing savings, and future-proofing.', 'TrendingUp',
 'It sounds early, but financial habits start forming now — yours, not just your child''s. The routines you build around spending, saving, and talking about money will shape your family''s financial culture. This is also a great time to increase savings rates as initial baby costs stabilize.',
 '[{"title": "Increase your savings rate by 2-5%", "description": "Initial baby costs have stabilized. Redirect the budget surplus to retirement or college savings before lifestyle inflation eats it."},{"title": "Start teaching money concepts", "description": "Toddlers can learn ''we buy things with money'' and ''when it''s gone, it''s gone.'' Use a piggy bank for visual learning."},{"title": "Review and consolidate accounts", "description": "Multiple savings accounts, unused credit cards, old retirement accounts. Simplify your financial life for better tracking."},{"title": "Plan for upcoming expenses", "description": "Preschool tuition, bigger car seat, toddler-proofing, activities and classes. Budget for the next 6-12 months."}]'::jsonb,
 '[{"quote": "I gave my 15-month-old a piggy bank. She can''t count, but she loves putting coins in. The habit starts now.", "attribution": "Michael, dad of one"},{"quote": "We bumped retirement contributions by 3% when our baby costs stabilized. Barely noticed the paycheck difference.", "attribution": "Kevin, dad of two"}]'::jsonb,
 3, true),

('finances', '18-plus', 'Protect and Grow', 'Annual financial review, insurance audit, and planning the next chapter.', 'ShieldCheck',
 'Your family financial system is established. Now it''s about maintaining, optimizing, and planning for what''s next. An annual financial review — insurance, investments, estate plan, budget — keeps everything on track. If another child is in the picture, you know the drill now, but the numbers change.',
 '[{"title": "Conduct an annual financial review", "description": "Insurance coverage, investment allocations, estate plan, budget accuracy. Set a calendar reminder and do it every year."},{"title": "Reassess childcare costs", "description": "As your child ages, costs shift. Preschool, activities, and eventually school-age care have different price points."},{"title": "Plan for potential family growth", "description": "If another child is possible, start modeling the costs now. Space planning, vehicle needs, childcare for two."},{"title": "Teach your toddler about choices", "description": "''We can get this OR that, but not both.'' Simple choice-making builds financial decision skills from toddlerhood."}]'::jsonb,
 '[{"quote": "Our annual money meeting takes 2 hours on a Sunday. We review everything, set goals, and then go get brunch. It''s actually become something we look forward to.", "attribution": "Scott, dad of three"},{"quote": "Realizing that two kids in daycare would cost more than our mortgage was a wake-up call. Glad we ran the numbers early.", "attribution": "Jason, dad of two"}]'::jsonb,
 3, true),

-- =============================================================================
-- ANXIETY PILLAR (pillar 4 of 7)
-- Managing stress, fears, and mental health
-- =============================================================================

('anxiety', 'pre-pregnancy', 'Name Your Fears', 'Acknowledge what scares you about becoming a dad.', 'CloudLightning',
 'Every soon-to-be dad has fears. ''What if I''m not ready?'' ''What if something goes wrong?'' ''What if I turn into my father?'' These thoughts are normal, and they''re not a sign of weakness — they''re a sign you care. The first step is getting them out of your head and into the open where they lose their power.',
 '[{"title": "Write down your top 5 fears", "description": "Actually write them. On paper, in a notes app, wherever. Making fears concrete makes them manageable instead of a vague dread."},{"title": "Talk to a dad you trust", "description": "Not for advice — for honesty. Ask them what scared them. You''ll be amazed how universal these fears are."},{"title": "Assess your mental health baseline", "description": "How are you sleeping? Drinking? Exercising? Stress-eating? Know your starting point so you can notice changes later."},{"title": "Research paternal mental health resources", "description": "Therapy, support groups, hotlines. Know what''s available BEFORE you need it. Postpartum depression affects dads too."}]'::jsonb,
 '[{"quote": "I was terrified I''d be like my dad. Writing that fear down was the first step to making sure I wouldn''t be.", "attribution": "Paul, dad of two"},{"quote": "My therapist told me that anxiety about being a good father is actually evidence that you will be. That reframe changed everything.", "attribution": "Leo, first-time dad"}]'::jsonb,
 4, false),

('anxiety', 'trimester-1', 'Manage the Uncertainty', 'First trimester anxiety is real — here''s how to handle it.', 'Shield',
 'The first trimester is peak anxiety for most dads. You can''t tell anyone, you can''t see the baby, and the miscarriage statistics are terrifying. Add in the fact that your partner needs support while you''re silently freaking out, and it''s a lot. You''re allowed to be scared AND excited at the same time.',
 '[{"title": "Limit your Google searches", "description": "Set a rule: one trusted source (like your OB or a pregnancy book) for medical questions. Dr. Google at 2am is anxiety fuel."},{"title": "Find one person to confide in", "description": "Even if you''re not telling everyone, you need someone. A friend, a sibling, a therapist. Carrying this alone makes it harder."},{"title": "Establish a daily stress release", "description": "Exercise, journaling, meditation, a walk — pick one thing you do every day that isn''t about pregnancy. Protect it."},{"title": "Attend the first ultrasound", "description": "Hearing the heartbeat transforms abstract anxiety into concrete reality. Move whatever you need to move to be there."}]'::jsonb,
 '[{"quote": "I Googled every symptom for the first two weeks. Then I deleted the browser tabs, bought a book, and my anxiety dropped 50%.", "attribution": "Mark, dad of one"},{"quote": "Hearing the heartbeat at 8 weeks didn''t eliminate my anxiety, but it gave it a counterweight. Hope.", "attribution": "Daniel, first-time dad"}]'::jsonb,
 4, false),

('anxiety', 'trimester-2', 'Find Your Calm', 'Build sustainable stress management habits now.', 'Wind',
 'The second trimester is often called the ''honeymoon trimester'' — anxiety drops, energy returns, and things feel more stable. Use this window to build stress management habits that will carry you through the intense months ahead. The coping mechanisms you establish now are the ones you''ll reach for at 3am with a screaming newborn.',
 '[{"title": "Start or deepen a mindfulness practice", "description": "Even 5 minutes of daily meditation or breathing exercises. Apps like Headspace or Calm have specific ''new parent'' programs."},{"title": "Build physical activity into your routine", "description": "Exercise is the most effective anxiety treatment that most people aren''t using. Whatever you enjoy — walk, run, lift, play — do it consistently."},{"title": "Practice talking about your feelings", "description": "With your partner, a friend, or a therapist. The muscle of expressing emotions gets stronger with use, and you''ll need it."},{"title": "Create a worry processing system", "description": "Dedicated worry time — 15 minutes a day where you let yourself think about concerns, then close the book. Containment reduces rumination."}]'::jsonb,
 '[{"quote": "I started running during the second trimester. By the time the baby came, it was non-negotiable ''dad time'' that kept me sane.", "attribution": "Travis, dad of one"},{"quote": "The worry journal sounds cheesy but it works. Writing it down gets it out of the loop in your head.", "attribution": "Noah, first-time dad"}]'::jsonb,
 4, false),

('anxiety', 'trimester-3', 'Prepare Your Mind for Delivery', 'Manage delivery anxiety and build mental resilience for birth day.', 'Anchor',
 'Delivery anxiety is a specific, intense flavor of fear. You''re about to watch the person you love most in pain, in a setting you don''t control, with stakes that couldn''t be higher. This is normal. But preparation — mental, emotional, and practical — is the antidote. You can''t control what happens, but you can control how ready you are.',
 '[{"title": "Visualize the delivery positively", "description": "Not denial — realistic optimism. Imagine yourself calm, supportive, present. Your brain rehearses what you visualize."},{"title": "Learn comfort techniques", "description": "Counter-pressure for back labor, breathing coaching, ice chip duty, hand-holding stamina. Practice with your partner."},{"title": "Identify your anxiety triggers", "description": "Blood? Needles? Loss of control? Knowing your triggers lets you prepare specific coping strategies."},{"title": "Have a ''dad support'' person on call", "description": "Someone you can text from the hospital who will respond. Not to vent to your partner — to process separately."}]'::jsonb,
 '[{"quote": "I told the nurse I was afraid of blood. She positioned me at my wife''s head and talked me through it. No shame in asking.", "attribution": "Grant, dad of one"},{"quote": "I visualized being calm in the delivery room every night for a month. When the moment came, it was like muscle memory.", "attribution": "Robert, first-time dad"}]'::jsonb,
 4, false),

('anxiety', '0-3-months', 'Survive the Anxiety Spike', 'Newborn anxiety is intense — here''s how to cope without drowning.', 'LifeBuoy',
 'The first three months with a newborn are an anxiety pressure cooker. Sleep deprivation amplifies everything. Every sound, every silence, every Google search spirals. Paternal postpartum anxiety and depression are real — affecting up to 25% of new dads. This isn''t weakness. It''s biology plus circumstance. Know the signs and have a plan.',
 '[{"title": "Monitor your own mental health", "description": "Take the Edinburgh Postnatal Depression Scale (EPDS) — it works for dads too. Score above 10? Talk to your doctor. No shame, just data."},{"title": "Maintain one non-negotiable self-care habit", "description": "Exercise, sleep, social connection — pick the one that keeps you most stable and protect it fiercely."},{"title": "Limit SIDS anxiety with action", "description": "Follow safe sleep guidelines perfectly, then stop checking every 5 minutes. Anxiety without action is just suffering. Action without anxiety is prevention."},{"title": "Talk to your partner about how you''re really doing", "description": "Not ''I''m fine.'' Really doing. She may be feeling the same way, and shared vulnerability builds connection."}]'::jsonb,
 '[{"quote": "I was checking on him every 10 minutes while he slept. My wife finally said ''you need to talk to someone.'' She was right. Therapy helped.", "attribution": "Brad, dad of one"},{"quote": "The EPDS screening at the pediatrician''s office caught my wife''s PPD early. Nobody screened me. I wish they had.", "attribution": "Anthony, first-time dad"}]'::jsonb,
 4, false),

('anxiety', '3-6-months', 'Build Long-Term Resilience', 'Move from crisis mode to sustainable mental wellness.', 'HeartPulse',
 'The acute crisis period is easing. Sleep is improving (hopefully), and you''re starting to feel like yourself again. This is the perfect window to convert survival-mode coping into sustainable mental health habits. The dads who build resilience now are the ones who handle toddler tantrums without losing it.',
 '[{"title": "Reassess your mental health", "description": "How are you really doing now that the fog is lifting? Sometimes anxiety hides during the crisis and surfaces when things calm down."},{"title": "Strengthen your support network", "description": "Join a dad group, reconnect with friends, deepen one relationship. Isolation is the enemy of mental health."},{"title": "Develop a stress response protocol", "description": "When overwhelmed: put baby in safe place, step away for 2 minutes, breathe, return. Practice this before you need it."},{"title": "Celebrate what you''ve survived", "description": "Seriously. You made it through the hardest part. Acknowledging that builds confidence for the challenges ahead."}]'::jsonb,
 '[{"quote": "I joined a dads group at the rec center. Thought it would be awkward. Now they''re some of my closest friends.", "attribution": "Tim, dad of one"},{"quote": "My therapist said ''you survived the hardest three months of your life and you''re still here.'' I cried. In a good way.", "attribution": "Victor, first-time dad"}]'::jsonb,
 4, false),

('anxiety', '6-12-months', 'Manage the New Worries', 'Safety anxiety, comparison traps, and finding your confidence.', 'Eye',
 'A mobile baby brings a whole new category of anxiety. Choking hazards, falls, bumps, and the constant vigilance required is exhausting. Add in the comparison trap — other babies crawling, talking, sleeping better — and your anxiety has fresh fuel. This is where you learn to distinguish reasonable caution from anxious overprotection.',
 '[{"title": "Distinguish risk from anxiety", "description": "Some fears are legitimate safety concerns (choking hazards, stairs). Some are anxiety (they''ll never walk, they''re behind). Learn to tell the difference."},{"title": "Take a baby CPR/first aid class", "description": "Competence kills anxiety. Knowing you can handle a choking incident transforms fear into readiness."},{"title": "Stop comparing your baby", "description": "Milestones have wide ranges. Your baby isn''t behind because the neighbor''s kid walked first. Talk to your pediatrician if genuinely concerned."},{"title": "Practice controlled risk-taking", "description": "Let them fall (safely). Let them struggle (briefly). Let them fail (gently). Building resilience in your child requires managing anxiety in yourself."}]'::jsonb,
 '[{"quote": "The CPR class was the single best thing I did for my anxiety. I went from ''what if he chokes'' to ''I know exactly what to do.''", "attribution": "Brian, dad of one"},{"quote": "My buddy''s kid walked at 9 months. Mine walked at 14 months. They both walk fine now. The comparison was pointless.", "attribution": "Corey, dad of two"}]'::jsonb,
 4, true),

('anxiety', '12-18-months', 'Let Go of Perfect', 'Embrace ''good enough'' parenting and release the pressure.', 'Feather',
 'By now you''ve had a year of parenting, and the pressure to be perfect might be building. Social media dads with perfect nurseries and curated activities. Parenting books with conflicting advice. Your own internal critic. Good enough parenting isn''t settling — it''s science. Research consistently shows that ''good enough'' is optimal for child development.',
 '[{"title": "Identify your perfectionism triggers", "description": "Where do you feel the most pressure to be perfect? Screen time? Nutrition? Education? Name it so you can challenge it."},{"title": "Practice self-compassion", "description": "Talk to yourself like you''d talk to a friend who was struggling. You would never tell a friend they''re a bad dad. Don''t say it to yourself."},{"title": "Set realistic expectations", "description": "Your toddler will eat chicken nuggets. They will watch some TV. You will lose your patience. None of this makes you a bad parent."},{"title": "Reconnect with joy", "description": "When was the last time you did something with your kid just for fun? No developmental purpose, no milestone tracking — just play."}]'::jsonb,
 '[{"quote": "I realized I was so focused on ''enriching activities'' that I forgot how to just sit on the floor and play cars. My son didn''t need enrichment. He needed me.", "attribution": "Cody, dad of one"},{"quote": "My therapist introduced me to ''good enough parenting.'' It felt like permission to breathe.", "attribution": "Marcus, dad of two"}]'::jsonb,
 4, true),

('anxiety', '18-plus', 'Model Emotional Health', 'Your toddler is watching — show them what healthy coping looks like.', 'Heart',
 'Here''s the thing about toddlers: they''re always watching. How you handle frustration, stress, and disappointment is programming their emotional operating system. This isn''t more pressure — it''s motivation. When you model taking a deep breath instead of yelling, you''re teaching them something no class ever could.',
 '[{"title": "Narrate your emotions", "description": "''Daddy is frustrated right now. I''m going to take a deep breath.'' This teaches emotional vocabulary AND coping in real time."},{"title": "Apologize when you mess up", "description": "You will lose your temper. What matters is what happens next. ''I''m sorry I yelled. That wasn''t kind'' teaches repair."},{"title": "Maintain your mental health practices", "description": "Whatever works for you — therapy, exercise, meditation, social connection. Keep doing it. Your family depends on a healthy you."},{"title": "Recognize when you need help", "description": "If anxiety is increasing, if you''re drinking more, if you''re withdrawing — these are signals, not failures. Act on them."}]'::jsonb,
 '[{"quote": "My 2-year-old saw me take a deep breath when I was frustrated and said ''breathe, Daddy.'' I almost cried. He was learning from me.", "attribution": "Jake, dad of one"},{"quote": "Going back to therapy when my son turned 18 months wasn''t a sign I was struggling. It was a sign I was paying attention.", "attribution": "Nathan, dad of two"}]'::jsonb,
 4, true),

-- =============================================================================
-- BABY BONDING PILLAR (pillar 5 of 7)
-- Building connection with baby (during pregnancy and after)
-- =============================================================================

('baby_bonding', 'pre-pregnancy', 'Start Imagining Your Relationship', 'Bond with the idea of your future child.', 'Sparkles',
 'Bonding with your baby starts before conception — it starts with imagination. Thinking about the kind of dad you want to be, imagining the things you''ll do together, and getting emotionally ready for this relationship is real bonding work. It might feel abstract now, but it''s laying the foundation for the connection you''ll build.',
 '[{"title": "Write a letter to your future child", "description": "What do you hope for them? What do you want them to know about this time? It''s for you as much as them."},{"title": "Think about your own father", "description": "What did he do well? What would you do differently? This reflection shapes the dad you''ll become."},{"title": "Learn about father-child attachment", "description": "Dads bond differently than moms — and that''s not a deficiency. Research shows dad play, roughhousing, and adventure-seeking are crucial for development."},{"title": "Talk to your partner about parenting values", "description": "What kind of parents do you want to be? What matters most? These conversations build alignment before the chaos hits."}]'::jsonb,
 '[{"quote": "I wrote a letter to my future kid at 28. Read it again when my daughter was born. Absolutely wrecked me in the best way.", "attribution": "Kyle, dad of one"},{"quote": "Thinking about what I wanted to do differently than my dad gave me purpose before there was even a baby.", "attribution": "Eli, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', 'trimester-1', 'Connect Through the Invisible Phase', 'Your baby is tiny but your bond can start growing.', 'HeartHandshake',
 'Bonding in the first trimester is hard because there''s nothing to see, hold, or interact with. Your partner is experiencing the pregnancy physically — you''re experiencing it conceptually. That gap is real, and it''s okay. Bonding for dads in this phase is about engagement: going to appointments, learning together, and being emotionally present.',
 '[{"title": "Go to every appointment you can", "description": "Hearing the heartbeat together, seeing the first ultrasound — these shared experiences build your bond through shared awe."},{"title": "Talk about the baby with your partner", "description": "Names, hopes, fears. These conversations make the baby real before the bump does."},{"title": "Start a baby journal or photo album", "description": "Document the journey from the start. Ultrasound photos, your reactions, funny moments. You''ll treasure this later."},{"title": "Read or listen to a pregnancy book together", "description": "Shared knowledge creates shared language and shared excitement. Even 10 minutes before bed."}]'::jsonb,
 '[{"quote": "I felt nothing at the first ultrasound. Just a blob on a screen. Then they turned on the sound and I heard the heartbeat. Hit me like a truck.", "attribution": "Andre, dad of one"},{"quote": "We picked names during the first trimester. Calling her by name — even before we knew the sex — made everything more real.", "attribution": "Sam, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', 'trimester-2', 'Feel the Connection', 'Kicks, movements, and your first ''conversations'' with your baby.', 'Hand',
 'The second trimester is when bonding shifts from concept to sensation. You can feel the kicks. You can see the bump. And here''s something incredible: research shows babies can hear voices from about 18 weeks. Your baby is learning the sound of your voice right now. Talk to them. Read to them. Sing badly to them. They''re listening.',
 '[{"title": "Talk and read to the bump", "description": "Your voice is deeper and carries differently — babies respond to it. Read a book, tell stories about your day, or just say hello."},{"title": "Feel and respond to kicks", "description": "When your partner says ''the baby is kicking,'' drop what you''re doing. Put your hand there. Respond. These moments are finite."},{"title": "Attend the anatomy scan together", "description": "Seeing your baby''s face, counting fingers and toes — this is bonding in its purest form. Be there."},{"title": "Create a baby playlist", "description": "Music you love, songs from your childhood, things you want to share. Play it near the bump. They''ll recognize it after birth."}]'::jsonb,
 '[{"quote": "I read Harry Potter to the bump every night. When she was born, she''d calm down when I read in the same voice. Coincidence? I don''t think so.", "attribution": "Patrick, dad of one"},{"quote": "The first time I felt a kick respond to my hand, I just sat there stunned. That was a person in there, and they knew I was here.", "attribution": "Jake, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', 'trimester-3', 'Prepare to Meet Your Baby', 'Visualization, nesting, and emotional readiness.', 'Star',
 'You''re weeks away from meeting your child. The bonding work now is about emotional preparation — letting yourself feel the magnitude of what''s about to happen. Nest. Set up the nursery. Wash the tiny clothes. Hold the tiny socks and let it hit you. These moments of anticipation are bonding.',
 '[{"title": "Set up the nursery or baby space yourself", "description": "Assembling the crib, arranging the room, hanging something on the wall. Making a space for your child with your own hands is deeply bonding."},{"title": "Practice infant care skills", "description": "Diaper a teddy bear. Practice swaddling. It sounds silly, but physical preparation builds confidence that enables bonding."},{"title": "Write your birth day intentions", "description": "Not a birth plan — intentions for yourself. ''I will be calm. I will be present. I will hold my baby first chance I get.''"},{"title": "Plan skin-to-skin time", "description": "Discuss with your partner and birth team: you want skin-to-skin contact as soon as possible. This triggers bonding hormones in dads too."}]'::jsonb,
 '[{"quote": "I assembled the crib alone on a Saturday morning. Sat in the rocker when I was done and just stared at it. That''s when I became a dad.", "attribution": "Miguel, dad of two"},{"quote": "Skin-to-skin in the delivery room — my daughter stopped crying the moment she was on my chest. Nothing in my life has ever felt like that.", "attribution": "Joel, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', '0-3-months', 'Build the Foundation Bond', 'Skin-to-skin, feeding, and finding your role.', 'Baby',
 'The first three months are where your bond goes from theoretical to visceral. Skin-to-skin contact releases oxytocin in both of you. Feeding (whether bottle or supporting breastfeeding) creates intimacy. And here''s the secret: babies don''t need you to be perfect — they need you to be present. Show up, hold them, talk to them, and the bond builds itself.',
 '[{"title": "Do daily skin-to-skin time", "description": "Shirt off, baby on your chest. 20-30 minutes. This isn''t just nice — it regulates their temperature, heart rate, and builds attachment."},{"title": "Take a feeding role", "description": "Whether giving a bottle or bringing the baby to mom for nursing, feeding time is bonding time. Be involved, not a bystander."},{"title": "Master one soothing technique", "description": "The bounce-walk, the shush-pat, the football hold. Find the ONE thing that calms your baby when nothing else works. That''s your superpower."},{"title": "Have dedicated solo time with baby", "description": "Send your partner out. Handle everything alone for a few hours. Competence and confidence come from practice, not observation."}]'::jsonb,
 '[{"quote": "For the first month, the only way he''d stop crying was the bounce-walk. Drove me crazy. Now I miss it more than anything.", "attribution": "Ryan, dad of one"},{"quote": "My wife went to get coffee for two hours and I was terrified. By the time she came back, I felt like a real dad for the first time.", "attribution": "Chris, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', '3-6-months', 'Become Their Favorite Person', 'Interactive play, routines, and building your unique bond.', 'Smile',
 'Between 3 and 6 months, bonding goes from one-directional to interactive. Your baby smiles at you, laughs at your faces, reaches for you, and recognizes your voice across the room. This is the payoff for all those early weeks. Lean in. Play big. Be silly. The bond you''re building now shapes their attachment style for life.',
 '[{"title": "Develop signature play routines", "description": "Airplane, peek-a-boo, raspberry on the belly — create rituals that are uniquely yours. Babies love repetition and anticipation."},{"title": "Own a daily routine", "description": "Bath time, bedtime story, morning wake-up — pick one daily routine and make it yours. Consistency builds trust and attachment."},{"title": "Get on the floor and play", "description": "Down at their level, face to face. Tummy time together, rolling a ball, making faces. Floor time is bonding time."},{"title": "Narrate your world to them", "description": "''We''re going to the kitchen. I''m making coffee. See the dog? That''s Rex.'' You''re building language AND connection."}]'::jsonb,
 '[{"quote": "Bath time became ''our thing.'' She''d start kicking her legs with excitement when she heard the water. That reaction was better than any promotion I''ve ever gotten.", "attribution": "Dan, dad of one"},{"quote": "My wife asked why our daughter stops crying when I pick her up. It''s because I''ve held her every single day since birth. The bond is real.", "attribution": "Theo, first-time dad"}]'::jsonb,
 5, false),

('baby_bonding', '6-12-months', 'Deepen Through Play and Presence', 'Adventure, exploration, and becoming their safe base.', 'Mountain',
 'Your baby is exploring the world now, and you are their safe base — the person they crawl back to when things get scary, the person they look at for reassurance, the person whose approval lights up their face. Deepen this bond through adventure. Take them to new places. Show them new things. Be the parent who says yes to exploration.',
 '[{"title": "Take solo outings with your baby", "description": "The park, the grocery store, a walk around the block. Solo adventures build confidence for both of you and create your own stories."},{"title": "Introduce safe challenges", "description": "Climbing cushions, new textures, different environments. Being the parent who encourages exploration is a uniquely dad role."},{"title": "Respond consistently to bids for attention", "description": "When they look at you, point at something, or bring you a toy — respond every time. These ''bids'' are the building blocks of secure attachment."},{"title": "Create a bedtime ritual", "description": "Story, song, goodnight tour of the room. Bedtime rituals with dad provide security and predictability that deepens over years."}]'::jsonb,
 '[{"quote": "Every Saturday morning we go to the park. Just us. She''s 10 months old and can''t tell me she looks forward to it, but I know she does.", "attribution": "Alex, dad of one"},{"quote": "He brought me a book for the first time at 9 months. Climbed in my lap and waited. I read that book 47 times that week. Happily.", "attribution": "Jamal, first-time dad"}]'::jsonb,
 5, true),

('baby_bonding', '12-18-months', 'Bond Through Teaching', 'Your toddler wants to learn from YOU — embrace the role.', 'Lightbulb',
 'Your toddler is a sponge, and you are their favorite teacher. They want to do what you do, go where you go, and learn what you know. This imitation is the deepest form of bonding — they''re saying ''I want to be like you.'' Welcome it. Show them how things work. Let them help. Be patient with the mess.',
 '[{"title": "Involve them in your activities", "description": "Cooking, fixing things, washing the car, exercising. They can''t really help, but including them sends the message: you belong here."},{"title": "Follow their lead in play", "description": "Let them choose the activity. Sit down and do whatever they''re doing. Child-led play builds confidence and trust."},{"title": "Read together every day", "description": "Not because it''s developmental — because a toddler in your lap with a book is one of life''s best moments. Protect this time."},{"title": "Create a special daddy-and-me tradition", "description": "Saturday pancakes, Sunday park trip, Friday pizza night. Something predictable that belongs to just the two of you."}]'::jsonb,
 '[{"quote": "My daughter ''helps'' me make pancakes every Saturday. She mostly just eats the blueberries. It''s my favorite hour of the week.", "attribution": "Adam, dad of one"},{"quote": "He follows me around the house with a toy hammer when I do anything. It''s inefficient and wonderful.", "attribution": "Pete, dad of two"}]'::jsonb,
 5, true),

('baby_bonding', '18-plus', 'Be Their Adventure Partner', 'Push boundaries together and build a bond that lasts.', 'Compass',
 'Your toddler is becoming a person with interests, preferences, and a growing sense of adventure. This is where the fun really begins. You can go places, do things, have real (simple) conversations, and start building the kind of memories you''ll both remember. Be the dad who says ''let''s go find out'' instead of ''not right now.''',
 '[{"title": "Plan regular adventures", "description": "The zoo, a hike, the museum, a new playground. Regular adventures teach your child that the world is exciting and you''re the one who shows it to them."},{"title": "Start a shared hobby", "description": "Building with blocks, kicking a ball, drawing, music. Find something you both genuinely enjoy and make it your thing."},{"title": "Have conversations, not just instructions", "description": "Ask questions, wait for answers, respond to what they say. Even with limited vocabulary, real conversation builds deep connection."},{"title": "Let them see you try new things", "description": "Model curiosity and bravery. When they see you try (and sometimes fail), they learn that effort matters more than perfection."}]'::jsonb,
 '[{"quote": "We went to the aquarium and my son just stood in front of the jellyfish tank for 20 minutes. I stood there with him. Sometimes bonding is just being still together.", "attribution": "Darius, dad of one"},{"quote": "My daughter and I garden together. She''s 2 and mostly just digs holes. But she runs to the garden every morning to check ''our'' plants.", "attribution": "Ian, dad of two"}]'::jsonb,
 5, true),

-- =============================================================================
-- RELATIONSHIP PILLAR (pillar 6 of 7)
-- Maintaining partner relationship through transition
-- =============================================================================

('relationship', 'pre-pregnancy', 'Strengthen Before the Storm', 'Invest in your relationship before baby changes the dynamic.', 'Users',
 'Every relationship advisor will tell you: the couples who do best through the transition to parenthood are the ones who were strongest going in. This isn''t about being perfect — it''s about building communication patterns, resolving existing tensions, and creating a partnership foundation that can handle the stress ahead.',
 '[{"title": "Have the big conversations", "description": "Parenting philosophy, division of labor, career priorities, finances, values. Get aligned on the big stuff before a newborn makes every conversation harder."},{"title": "Establish a conflict resolution pattern", "description": "How do you fight? How do you repair? Develop a process now — something like: cool down, name the issue, hear each other, find a solution."},{"title": "Schedule regular connection time", "description": "Date nights, walks, device-free dinners. Build the habit of prioritizing your relationship before it has to compete with a baby."},{"title": "Consider couples counseling", "description": "Not because you''re broken — because you''re about to face the biggest transition of your life together. A tune-up, not a repair."}]'::jsonb,
 '[{"quote": "We did 8 sessions of couples counseling before trying to conceive. Best investment we ever made. We had tools when the hard parts hit.", "attribution": "Ross, dad of one"},{"quote": "The conversation about division of labor before pregnancy was 100x easier than having it with a screaming newborn at 3am.", "attribution": "Troy, first-time dad"}]'::jsonb,
 6, false),

('relationship', 'trimester-1', 'Show Up During the Hard Part', 'Your partner is going through it — be the teammate she needs.', 'HandHeart',
 'First trimester is often the hardest stretch for your partner: constant nausea, crushing fatigue, hormonal mood swings, and she can''t even talk about it yet. Your job isn''t to fix it — it''s to show up. Take over chores without being asked. Don''t take mood shifts personally. And when she says she''s tired for the third time today, just say ''I believe you.''',
 '[{"title": "Take over household tasks proactively", "description": "Don''t wait to be asked. Cooking, cleaning, groceries, laundry. If she''s too nauseous to cook, handle meals without making it a thing."},{"title": "Learn her love language (again)", "description": "What made her feel loved before might not work now. Acts of service often jump to #1 during pregnancy. Adjust."},{"title": "Don''t offer solutions — offer presence", "description": "''That sounds really hard'' beats ''have you tried ginger?'' every time. She knows about ginger. She wants to be heard."},{"title": "Manage your own expectations", "description": "Sex, social life, energy levels — everything changes. Adjust your expectations and communicate about the changes without resentment."}]'::jsonb,
 '[{"quote": "She threw up every morning for 8 weeks. I held her hair, brought crackers, and didn''t say a word about the mess. That''s how you show up.", "attribution": "Keith, dad of one"},{"quote": "When I stopped trying to fix her nausea and just said ''that must be so miserable,'' she actually relaxed. She didn''t need a solution. She needed empathy.", "attribution": "Wyatt, first-time dad"}]'::jsonb,
 6, false),

('relationship', 'trimester-2', 'Reconnect and Recharge', 'Use the feel-good trimester to strengthen your partnership.', 'HeartPulse',
 'The second trimester often brings relief — nausea fades, energy returns, and the glow is real. This is your window to reconnect as a couple. Go on dates. Have the fun conversations about names and nursery colors. Remember why you chose each other. The goodwill you build now is the savings account you''ll withdraw from in the postpartum fog.',
 '[{"title": "Plan intentional date nights", "description": "Dinner out, movie, a walk. Anything that feels like ''us time'' instead of ''baby prep time.'' You need both."},{"title": "Take a babymoon", "description": "Doesn''t have to be fancy — a weekend away, a staycation, even a nice dinner. Mark the transition from couple to parents."},{"title": "Talk about each other, not just the baby", "description": "Ask about work, dreams, how she''s feeling about herself — not just the pregnancy. She''s still a whole person."},{"title": "Discuss postpartum expectations honestly", "description": "Sleep, visitors, division of labor, sex, mental health. These conversations are easier now than at week 38."}]'::jsonb,
 '[{"quote": "We took a weekend trip at 22 weeks. Nothing fancy — just a cabin and quiet. We''ve never been more grateful for a trip.", "attribution": "Taylor, dad of one"},{"quote": "She mentioned feeling invisible behind the bump. So I planned a date that had nothing to do with baby. She cried happy tears.", "attribution": "Connor, first-time dad"}]'::jsonb,
 6, false),

('relationship', 'trimester-3', 'Team Up for Delivery', 'Become a birth team, not just a birth spectator.', 'Shield',
 'The third trimester is when partnership gets tested. She''s uncomfortable, anxious, and over it. You might be scared, overwhelmed, and unsure how to help. The answer is to become a team with a shared goal: get through delivery together. Take the classes together, practice the breathing together, know the birth plan together. You''re not a spectator — you''re her teammate.',
 '[{"title": "Attend childbirth class together", "description": "Not just to learn — to practice being a support team. You''ll use these skills during the most intense experience of your lives."},{"title": "Know her birth preferences cold", "description": "If she can''t advocate for herself, you need to. Know what she wants, what she''s flexible on, and what''s non-negotiable."},{"title": "Practice being her physical support", "description": "Counter-pressure, positioning, breathing coaching. Learn these hands-on so they''re automatic, not theoretical."},{"title": "Have the postpartum plan conversation", "description": "Who''s coming to help? Who''s not? How long is her maternity leave? When is yours? Align on everything now."}]'::jsonb,
 '[{"quote": "During labor, I applied counter-pressure exactly how we practiced. She later said it was the only thing that helped. That''s what teamwork looks like.", "attribution": "Ethan, dad of one"},{"quote": "The nurse asked me what the birth plan was. I rattled it off without hesitation. My wife squeezed my hand and I knew we were a team.", "attribution": "Carlos, first-time dad"}]'::jsonb,
 6, false),

('relationship', '0-3-months', 'Protect Your Partnership', 'The newborn phase will test you — fight for your relationship.', 'Lock',
 'The transition to parenthood is the single biggest stressor most couples will ever face. Satisfaction plummets. Resentment builds. Sleep deprivation turns minor annoyances into volcanic fights. This is not a sign your relationship is failing — it''s a sign you''re going through something incredibly hard. The couples who make it are the ones who fight for the relationship, not with each other.',
 '[{"title": "Establish a daily check-in", "description": "Even 5 minutes: ''How are you? What do you need? What can I do?'' Daily micro-connections prevent the drift that leads to resentment."},{"title": "Split duties fairly, not equally", "description": "Fair means accounting for recovery, breastfeeding, and capacity. Equal is a myth that breeds scorekeeping."},{"title": "Express gratitude out loud", "description": "''Thank you for getting up with him last night.'' Acknowledgment is the antidote to resentment. Give it freely."},{"title": "Fight fair when conflict comes", "description": "No scorekeeping, no character attacks, no ''you always.'' Address the specific issue. If you can''t do it calmly, table it until you can."}]'::jsonb,
 '[{"quote": "We almost didn''t make it through month two. Our therapist taught us ''daily check-ins'' and it was like oxygen for the relationship.", "attribution": "Frank, dad of one"},{"quote": "I started saying ''thank you'' for things I used to take for granted. She started doing the same. The whole tone of our house changed.", "attribution": "Gavin, first-time dad"}]'::jsonb,
 6, false),

('relationship', '3-6-months', 'Rebuild Your Connection', 'Moving past survival mode back to actual partnership.', 'Puzzle',
 'The survival fog is lifting and you can start seeing each other as partners again, not just co-workers on the parenting shift. But reconnection doesn''t happen automatically — you have to be intentional about it. Date nights, physical affection, real conversations, and shared experiences outside of baby care rebuild what sleep deprivation eroded.',
 '[{"title": "Reinstate date night", "description": "At home after baby sleeps counts. Order food, put phones away, and talk about something other than the baby for one hour."},{"title": "Discuss physical intimacy openly", "description": "Desire, readiness, concerns, changes. This conversation is awkward and necessary. Approach it with zero pressure and full honesty."},{"title": "Identify and address resentment early", "description": "If you''re keeping score, something is off. Name it: ''I feel like I''m doing more of X.'' Handle it before it metastasizes."},{"title": "Dream together again", "description": "Vacations, goals, house plans, career moves. Talking about the future together reminds you that you''re building a life, not just surviving one."}]'::jsonb,
 '[{"quote": "Our first date night was takeout on the couch after the baby slept. We talked for two hours and it felt like falling in love again.", "attribution": "Simon, dad of one"},{"quote": "We had the intimacy conversation at 4 months. It was uncomfortable for 10 minutes and relieving for weeks after.", "attribution": "Marco, first-time dad"}]'::jsonb,
 6, false),

('relationship', '6-12-months', 'Grow Together as Parents', 'Find your parenting partnership rhythm.', 'Handshake',
 'By now, you have a parenting rhythm. But rhythms can become ruts if you don''t keep investing. This phase is about deepening your partnership — not just dividing tasks, but truly co-parenting. Supporting each other''s parenting styles, having each other''s backs in front of the kids, and continuing to prioritize each other alongside the baby.',
 '[{"title": "Align on parenting approaches", "description": "Discipline, sleep, feeding, screen time. You don''t have to agree on everything, but you need a united front. Discuss differences privately."},{"title": "Support each other''s alone time", "description": "Both of you need time that''s not parenting and not work. Protect each other''s recharge time actively and without guilt trips."},{"title": "Plan a couples getaway", "description": "Even one night away. Leave the baby with trusted family. Reconnecting without your child in the room is different and necessary."},{"title": "Express appreciation for specific parenting wins", "description": "''The way you handled that tantrum was amazing.'' Specific praise builds confidence and connection."}]'::jsonb,
 '[{"quote": "We took one night away for our anniversary. Felt guilty for about 20 minutes, then remembered why we got married in the first place.", "attribution": "Cole, dad of one"},{"quote": "My wife parents differently than I do. I used to think that meant one of us was wrong. Now I know it means our kid gets two perspectives.", "attribution": "Andy, dad of two"}]'::jsonb,
 6, true),

('relationship', '12-18-months', 'Navigate the Toddler Dynamic', 'Parenting disagreements, division of labor shifts, and staying close.', 'MessagesSquare',
 'Toddlerhood introduces new relationship dynamics. You''ll disagree about discipline. One of you will be the ''fun parent'' and the other the ''rule parent.'' The division of labor shifts as childcare demands change. These are normal pressures — they become problems only when you stop communicating about them.',
 '[{"title": "Discuss discipline philosophy together", "description": "Time-outs, redirection, natural consequences, boundaries. Agree on an approach before you need it, not during a tantrum."},{"title": "Rebalance household duties", "description": "What worked with a baby might not work with a toddler. Audit who''s doing what and adjust for the current reality."},{"title": "Don''t undermine each other''s parenting", "description": "If you disagree with how your partner handled something, discuss it later. Never in front of the toddler. United front."},{"title": "Keep investing in couple time", "description": "It''s easy to let date nights slip when the baby becomes a toddler. Don''t. Your relationship is the foundation your family stands on."}]'::jsonb,
 '[{"quote": "We disagreed about time-outs. Instead of fighting, we read the same parenting book and discussed it. Found common ground.", "attribution": "Greg, dad of one"},{"quote": "My wife told me she felt like the ''bad cop'' and I was always the fun one. That was hard to hear and important to fix.", "attribution": "Wes, dad of two"}]'::jsonb,
 6, true),

('relationship', '18-plus', 'Keep Choosing Each Other', 'Your relationship needs attention beyond co-parenting.', 'Heart',
 'At this point, it''s easy to become co-parents who happen to live together. You know the routines, you split the duties, you function. But functioning isn''t thriving. The couples who thrive after kids are the ones who remember they''re lovers and friends, not just teammates. Keep dating. Keep talking. Keep choosing each other.',
 '[{"title": "Schedule a recurring date night", "description": "Weekly or biweekly, on the calendar, non-negotiable. Babysitter, grandparents, trade with another couple — make it happen."},{"title": "Check in on your relationship health", "description": "''How are WE doing?'' Not the family, not the house — us. Ask this regularly and listen to the answer without defensiveness."},{"title": "Pursue a shared interest", "description": "Something that''s yours as a couple, not as parents. Cooking, hiking, a show you watch together, a game. Feed the friendship."},{"title": "Consider a relationship tune-up", "description": "A couples workshop, a book you read together, or a few therapy sessions. Maintenance is cheaper than repair."}]'::jsonb,
 '[{"quote": "We almost became roommates who co-parent. A weekend away together reminded us that we actually really like each other.", "attribution": "Dustin, dad of two"},{"quote": "Our Tuesday date night is sacred. The kids know it. We know it. Protecting that time saved our marriage.", "attribution": "Sean, dad of three"}]'::jsonb,
 6, true),

-- =============================================================================
-- EXTENDED FAMILY PILLAR (pillar 7 of 7)
-- Managing family dynamics, boundaries, support
-- =============================================================================

('extended_family', 'pre-pregnancy', 'Map Your Support Network', 'Know who your people are before you need them.', 'Network',
 'Extended family is either your greatest asset or your greatest stressor — sometimes both on the same day. Before you even announce a pregnancy, understand the landscape. Who will be supportive? Who will be overbearing? Who will show up with food, and who will show up with unsolicited advice? Mapping this now helps you set expectations and boundaries proactively.',
 '[{"title": "Assess your family dynamics honestly", "description": "Who''s helpful vs. overbearing? Who respects boundaries vs. who stomps them? Be honest so you can plan accordingly."},{"title": "Discuss each family''s role with your partner", "description": "How involved do you want each set of grandparents? What are the non-negotiables? Get aligned before announcing."},{"title": "Identify your support crew", "description": "The 3-5 people you''ll actually call when things get hard. Not your whole contact list — your real crew."},{"title": "Think about boundary strategies", "description": "How will you handle unwanted advice, unannounced visits, or conflicting parenting philosophies from family?"}]'::jsonb,
 '[{"quote": "We made a literal list: column A is people who help without drama, column B is people who help with drama. Made our postpartum visitor list much easier.", "attribution": "Luis, dad of one"},{"quote": "The hardest conversation I had was with my mom about boundaries. But having it before the baby was born meant she had time to adjust instead of feeling attacked.", "attribution": "Trent, first-time dad"}]'::jsonb,
 7, false),

('extended_family', 'trimester-1', 'Navigate the Announcement', 'When, how, and who to tell — and managing everyone''s reactions.', 'Megaphone',
 'Announcing a pregnancy is exciting, but it also opens the floodgates of family input. Suddenly everyone has an opinion about names, parenting, hospital choices, and whether you''re having a boy or girl. Managing the announcement and the reactions that follow sets the tone for how involved your families will be. Set that tone intentionally.',
 '[{"title": "Agree on timing and method together", "description": "Parents first? Everyone at once? Social media? Make this decision as a couple, not unilaterally."},{"title": "Prepare for varied reactions", "description": "Not everyone will react the way you hope. Some will cry with joy, some will start giving advice immediately. Both are expressions of caring."},{"title": "Set early boundaries kindly", "description": "''We''re not sharing the name until birth.'' ''We''ll share ultrasound photos with family only.'' Kind and firm."},{"title": "Discuss the miscarriage protocol", "description": "If something goes wrong, who knows? Who do you tell? This is a hard conversation but an important one in the first trimester."}]'::jsonb,
 '[{"quote": "We told my parents at 8 weeks because we''d want their support if anything went wrong. We told everyone else at 13 weeks. Both decisions were right for us.", "attribution": "Drew, dad of one"},{"quote": "My mother-in-law immediately started planning the nursery. We had to say ''we love your enthusiasm, and we want to do this ourselves.'' She got it.", "attribution": "Xavier, first-time dad"}]'::jsonb,
 7, false),

('extended_family', 'trimester-2', 'Set Healthy Boundaries', 'Manage expectations, advice, and involvement levels.', 'Fence',
 'By the second trimester, the news is out and family dynamics are in full effect. Grandparents-to-be are excited, family members have opinions, and you''re navigating competing expectations from two families. This is where boundaries get established — not as walls, but as guidelines that protect your family unit while keeping loved ones connected.',
 '[{"title": "Have the name conversation ground rules", "description": "''We''re keeping the name private'' or ''we''d love suggestions but the final choice is ours.'' Be clear before opinions arrive uninvited."},{"title": "Discuss grandparent roles and expectations", "description": "How often will they visit? Will they babysit? What''s their input on parenting decisions? Set expectations early."},{"title": "Address cultural or generational differences", "description": "Sleep positions, feeding, discipline — previous generations had different advice. Have a script: ''Thanks, our pediatrician recommends...''"},{"title": "Create a communication plan", "description": "How often will you share updates? Group text? Weekly photo? Managing information flow prevents hurt feelings."}]'::jsonb,
 '[{"quote": "When my mom said ''we never used car seats and you turned out fine,'' I needed a script. ''Things have changed, and we''re going to follow current safety guidelines'' worked every time.", "attribution": "Diego, dad of one"},{"quote": "We created a family group chat for baby updates. Controlled the narrative, kept everyone informed, and reduced the ''why didn''t you tell me?'' drama by 90%.", "attribution": "Malik, first-time dad"}]'::jsonb,
 7, false),

('extended_family', 'trimester-3', 'Plan the Postpartum Boundaries', 'Hospital visits, postpartum guests, and protecting your recovery bubble.', 'DoorOpen',
 'The third trimester is when you need to have the hard conversation: who''s at the hospital, who visits in the first week, and what the rules are. This is not about being controlling — it''s about protecting your partner''s recovery and your family''s bonding time. The first days with a newborn are sacred, and you are the gatekeeper.',
 '[{"title": "Decide who''s at the hospital", "description": "Delivery room: just you two? Waiting room: parents? Nobody until you call? Make the decision and communicate it clearly."},{"title": "Set postpartum visitor rules", "description": "Call before coming, 30-minute visits, bring food not flowers, wash hands, no kissing the baby. Write it down and send it out."},{"title": "Assign a family communication point person", "description": "During labor and delivery, you should be focused on your partner. Designate someone to relay updates to family."},{"title": "Plan family help strategically", "description": "If family is coming to help, assign specific tasks: cooking, laundry, older kids. Help should help, not create more work."}]'::jsonb,
 '[{"quote": "I told my family: no hospital visits until we call. My mother-in-law showed up anyway. That taught me that boundaries need to be firm, not just stated.", "attribution": "Raymond, dad of two"},{"quote": "My mom came for a week postpartum and only did cooking and laundry. Never held the baby unless we offered. Best help we ever had.", "attribution": "Nolan, first-time dad"}]'::jsonb,
 7, false),

('extended_family', '0-3-months', 'Manage the Grandparent Surge', 'Navigate the influx of family help, opinions, and emotions.', 'Users',
 'The baby is here and everyone wants to hold them. Grandparents are ecstatic, unsolicited advice is flowing, and family dynamics that were manageable before are now amplified by sleep deprivation and high emotions. Your job is to be the bridge between your families and your partner — protecting your bubble while keeping relationships intact.',
 '[{"title": "Enforce your visitor boundaries", "description": "The rules you set in the third trimester? Enforce them. People will test them. Be kind and firm."},{"title": "Redirect unsolicited advice gracefully", "description": "''Thanks, we''re going to try it this way for now.'' No debate, no defense, no justification needed."},{"title": "Facilitate grandparent bonding", "description": "Supervised, boundaried, and positive. Show them how to hold, feed, and interact with the baby your way."},{"title": "Protect your partner from family pressure", "description": "If your mother is pressuring about breastfeeding, sleep arrangements, or anything else — that''s your conversation to have, not hers."}]'::jsonb,
 '[{"quote": "My mother-in-law told my wife to stop breastfeeding and switch to formula. I told her, privately and firmly, that feeding decisions were ours. She backed off.", "attribution": "Kenneth, dad of one"},{"quote": "I learned that being the boundary enforcer is exhausting but necessary. My wife can''t fight with my family AND recover from childbirth.", "attribution": "Vince, first-time dad"}]'::jsonb,
 7, false),

('extended_family', '3-6-months', 'Find the Balance', 'Integrating family support without losing your boundaries.', 'Scale',
 'The initial surge has passed and now you''re finding a sustainable rhythm with family involvement. Some grandparents will settle into helpful roles; others may still push boundaries. The goal isn''t to shut family out — it''s to find the balance where their involvement enriches your family life without undermining your autonomy as parents.',
 '[{"title": "Establish regular grandparent time", "description": "Weekly visits, monthly dinners, video calls. Predictable access reduces anxiety and boundary-pushing."},{"title": "Coach grandparents on current practices", "description": "Sleep position, food introduction, car seat safety. Share it as ''exciting new research'' rather than ''you did it wrong.''"},{"title": "Address persistent boundary violations", "description": "If someone keeps ignoring your rules, have a direct conversation. Not angry — specific. ''When you do X, we feel Y. We need Z.''"},{"title": "Nurture the relationships that work", "description": "Double down on family members who respect boundaries and genuinely help. They deserve your gratitude and time."}]'::jsonb,
 '[{"quote": "We started Sunday dinners with my parents. Predictable, boundaried, and it became something everyone looked forward to instead of dreaded.", "attribution": "Jesse, dad of one"},{"quote": "I framed the ''no honey before one'' rule as ''cool new research'' instead of ''you''re wrong.'' My dad actually listened.", "attribution": "Terrence, first-time dad"}]'::jsonb,
 7, false),

('extended_family', '6-12-months', 'Build the Village', 'Turn family into reliable childcare and support partners.', 'Building',
 'If you''re lucky enough to have family nearby who wants to be involved, this is the phase where that involvement becomes genuinely valuable. A grandparent who knows your routine, follows your rules, and your baby is comfortable with is an incredible resource. Building that trust takes time, and the investment pays off for years.',
 '[{"title": "Train trusted family on your routines", "description": "Nap schedule, food restrictions, bedtime routine. Write it down, walk them through it, and do a practice run before solo care."},{"title": "Do trial babysitting sessions", "description": "Start with 1-2 hours, build up. This builds confidence for everyone — you, the grandparent, and the baby."},{"title": "Include family in milestone moments", "description": "First foods, first steps, first words — sharing these moments builds bonds and makes family feel valued."},{"title": "Address long-distance family challenges", "description": "Regular video calls, photo sharing, planned visits. Help distant family feel connected despite the miles."}]'::jsonb,
 '[{"quote": "My parents watched him for 3 hours while we went to dinner. When we came back, everyone was happy. It took 6 months of building trust to get there.", "attribution": "Neil, dad of one"},{"quote": "We video call my wife''s parents every Sunday. Our son now reaches for the screen when he hears their voices. Worth every minute.", "attribution": "Hector, first-time dad"}]'::jsonb,
 7, true),

('extended_family', '12-18-months', 'Navigate Toddler Family Dynamics', 'Spoiling, discipline disagreements, and grandparent boundaries.', 'Puzzle',
 'Toddlerhood introduces new family dynamics. Grandparents want to spoil. Your parenting choices will be questioned. Sugar, screen time, discipline, manners — everyone has an opinion about how you''re raising your toddler. This is where your boundary skills get refined, and where you learn the art of appreciating help without surrendering authority.',
 '[{"title": "Address spoiling boundaries", "description": "Grandparents giving unlimited treats or toys undermines your rules. Have the conversation: ''We love that you love them, but we need consistency.''"},{"title": "Align extended family on discipline approach", "description": "If grandparents discipline differently (or don''t discipline at all), clarify expectations. Your rules apply in their house too."},{"title": "Navigate holiday and tradition expectations", "description": "Whose family gets which holiday? How do you create your own traditions while honoring existing ones? Negotiate early."},{"title": "Strengthen the grandparent-toddler relationship", "description": "Encourage special activities: baking with grandma, garage time with grandpa. Unique relationships, not just babysitting."}]'::jsonb,
 '[{"quote": "My dad gave my son ice cream before dinner every visit. We had to say ''we love the tradition idea, but can it be after dinner?'' Small shift, big difference.", "attribution": "Jason, dad of one"},{"quote": "We alternate Thanksgiving and Christmas between families. Having a predictable rotation eliminated the annual negotiation stress.", "attribution": "Wayne, dad of two"}]'::jsonb,
 7, true),

('extended_family', '18-plus', 'Sustain Your Support Network', 'Long-term family relationships that serve your growing child.', 'TreePine',
 'As your child grows, family relationships evolve. Grandparents become more active playmates, cousins become friends, and extended family events become formative memories. Your role shifts from gatekeeper to facilitator — creating opportunities for your child to build their own relationships with family while maintaining the boundaries that protect your unit.',
 '[{"title": "Facilitate independent grandparent relationships", "description": "Sleepovers, special outings, phone calls. Your toddler can start building their own relationship with grandparents without you mediating every interaction."},{"title": "Create family traditions", "description": "Annual camping trips, holiday cookie baking, birthday dinners. Traditions give your child a sense of belonging and continuity."},{"title": "Model healthy family relationships", "description": "How you treat your parents and in-laws teaches your child about respect, boundaries, and love. They''re watching."},{"title": "Plan for evolving family needs", "description": "Aging parents, geographic changes, family growth. Think ahead about how your support network may change and how to adapt."}]'::jsonb,
 '[{"quote": "My daughter''s first sleepover at my parents'' house was terrifying for me and magical for her. Letting go a little was the best thing I did for everyone.", "attribution": "Chad, dad of one"},{"quote": "We started a ''cousin camp'' every summer — all the kids, grandparents'' house, three days. The kids talk about it all year.", "attribution": "Martin, dad of three"}]'::jsonb,
 7, true)

